def solve(music_tracks, gamma_frequency, theta_frequency):
    if not isinstance(music_tracks, list) or not all(isinstance(track, str) for track in music_tracks):
        raise ValueError("music_tracks must be a list of strings.")
    if not isinstance(gamma_frequency, (int, float)) or not (30 <= gamma_frequency <= 100):
        raise ValueError("gamma_frequency must be a number between 30 and 100.")
    if not isinstance(theta_frequency, (int, float)) or not (4 <= theta_frequency <= 8):
        raise ValueError("theta_frequency must be a number between 4 and 8.")

    modified_tracks = []
    for track in music_tracks:
        modified_track = f"{track} - Gamma: {gamma_frequency}Hz, Theta: {theta_frequency}Hz"
        modified_tracks.append(modified_track)

    return modified_tracks
